VALUES
  ('cpa-moex-00011', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司召開股東會時，就股東會之決議，下列何人所持有A公司股份數，算入A公司已發行股份 總數？', '["自然人甲持有之無表決權特別股1萬股", "A公司為於3年內轉讓予員工之目的而持有之10萬股", "A公司持有其已發行股份總數80%股份之B公司所持有之3萬股", "A公司雖未持有C公司股份，但其董事過半數與C公司相同，C公司所持有之2萬股"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00012', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為一家非公開發行股票之公司，該公司董事甲在某市擁有一塊土地。A公司近期擬向甲購 買該土地，則A公司與甲為該土地交易時，應由何人為公司之代表？', '["董事長", "獨立董事", "監察人", "總經理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00013', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司是一家從事食品零售的民營公司，該公司董事會擬現金發行新股一百萬股，以籌 措公司所需資金。依公司法之規定，原則上A公司應至少保留多少股份由公司員工承購？', '["五萬股", "十萬股", "十五萬股", "五十萬股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00014', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司持有B公司已發行有表決權股份總數60%之股份。A公司使B公司為不合營業常規之經 營，卻未於會計年度終了時為適當補償，致B公司受有損害，若A公司未對B公司為賠償時， 下列何者得以自己之名義，請求A公司對B公司為給付？', '["B公司之獨立董事", "對B公司有相當於B公司淨值5%債權之債權人", "繼續一年以上持有A公司已發行股份總數10%以上之股東", "A公司之目的事業主管機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00015', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司是一家依英國公司法設立登記的外國公司。依公司法之規定，下列敘述何者錯誤？', '["A公司應經認許，始得在我國境內營業", "A公司在我國境內設立分公司者，其名稱，應譯成中文，並標明其種類及國籍", "A公司若在我國境內設立分公司，應專撥其營業所用之資金，並指定代表為在我國境內之負責人", "A公司於法令限制內，與本國公司有同一之權利能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00016', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲、乙、丙三人擬設立A股份有限公司，欲向主管機關辦理設立登記。依公司法之規定，下列敘 述何者錯誤？', '["A公司應於代表公司之負責人就任後十五日內，向主管機關申請設立之登記", "A公司申請登記得委任代理人，代理人僅以會計師為限", "A公司各項登記文件，公司負責人或利害關係人，得聲敘理由請求查閱、抄錄或複製", "A公司得向主管機關申請公司外文名稱登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00017', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非公開發行之股份有限公司，依公司法之規定，下列敘述何者正確？', '["可不發行股票", "應於發行新股變更登記後1個月內發行股票", "應於發行新股變更登記後2個月內發行股票", "應於發行新股變更登記後3個月內發行股票"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00018', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者並非公司法明定之股份有限公司股東會召集權人？', '["監察人", "繼續3個月以上持有已發行股份總數過半數股份之股東", "董事長", "董事會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00019', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者為董事缺額時，股份有限公司應盡速召開股東臨時會補選之最低門檻？', '["全部退任", "三分之二", "過半", "三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00020', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A興櫃公司因其獨到的商業模式獲得廣大消費者的青睞，故欲上市募資以加速擴大其通路的市占 率。下列關於證券交易法及相關規定的說明，何者正確？', '["甲股東持有A公司相當大量的特別股，若於該公司上市前公開對不特定投資人介紹、勸誘購買 其出售的股份，也須向主管機關申報生效", "本法既採申報生效制，主管機關指定之機關即使基於公益必要原因，要求A公司在上市過程中 補正說明，仍應在收到申請書件即日起屆滿一定營業日，即讓其生效、不得有所延遲", "A公司上市案件經申報生效後，乙董事長即可在與外國機構投資人的公開聚會上，表示我國政 府亦認同申報書件內所提之商業模式廣獲市場青睞", "A公司曾於上市前公開對不特定人招募出售該公司的認股權憑證，因尚未上市，故尚無須向主 管機關申報生效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
